// Frases de física cuántica y hermetismo en rotación
const frases = [
  "El observador colapsa la ola de posibilidades — tú decides qué realidad manifiestas hoy.",
  "En el universo cuántico, nada está fijo hasta que lo mides. Tu intención es el instrumento.",
  "Como es arriba, es abajo; como es adentro, es afuera. Tus pensamientos construyen tu empresa.",
  "El principio de superposición: dos futuros existen al mismo tiempo hasta que actúas.",
  "La entropía aumenta sin acción. El orden es un acto de voluntad cuántica.",
  "Todo está conectado por campos no locales. Tu éxito resonará en quienes te rodean.",
  "El tiempo es una ilusión útil. El único momento de poder es ahora, en este estado cuántico.",
  "La mente es el molde, la realidad es la materia que llena ese molde — Hermes Trismegisto.",
  "Un fotón no elige su camino solo — interactúa. Tu red de contactos es tu interferencia constructiva.",
  "El vacío cuántico no está vacío: es el campo de todas las potencialidades. Úsalo."
];

// Selección por día de la semana (0=Dom, 1=Lun, ...) para rotación determinista
const fraseDelDia = frases[new Date().getDay() % frases.length];

// Datos de API status (Node 1)
const apiData = $input.all()[0];
let apiStatus = 'desconocido';
try {
  const statusBody = apiData.json;
  apiStatus = statusBody.status || statusBody.estado || 'ok';
} catch(e) {
  apiStatus = 'sin respuesta';
}

// Datos de cierre fiscal (Node 2) — manejamos errores
let alertasFiscales = '• Sin alertas SAT pendientes hoy ✅';
try {
  const cierreData = $('GET Cierre Mes Fiscal').all()[0];
  if (cierreData && cierreData.json) {
    const cierre = cierreData.json;
    const alertas = cierre.alertas || cierre.alerts || [];
    if (alertas.length > 0) {
      alertasFiscales = alertas.map(a => `• ${a}`).join('\n');
    }
  }
} catch(e) {
  alertasFiscales = '• No se pudo consultar calendario fiscal';
}

// Fecha formateada
const ahora = new Date();
const diasSemana = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const fechaTexto = `${diasSemana[ahora.getDay()]} ${ahora.getDate()} de ${meses[ahora.getMonth()]} de ${ahora.getFullYear()}`;

const mensaje = `🌅 *Buenos días Luis Daniel — HERMES 5:30 AM*

📊 *Sistema:*
• API: ${apiStatus}
• Fecha: ${fechaTexto}

🗓️ *Fiscal hoy:*
${alertasFiscales}

💡 *Física cuántica del día:*
_${fraseDelDia}_

🎯 *Top 3 de hoy — recuerda trabajar en:*
1\. Rotar TELEGRAM\_TOKEN
2\. Conseguir primer cliente pagando
3\. Configurar Meta WhatsApp API`;

return [{ json: { mensaje } }];
